import (
	context "context"
	fern "github.com/api-wide-base-path/fern"
	fernclient "github.com/api-wide-base-path/fern/client"
)

client := fernclient.NewClient()
err := client.Service.Post(
	context.TODO(),
	&fern.ServicePostRequest{
		PathParam:     "pathParam",
		ServiceParam:  "serviceParam",
		EndpointParam: 1,
		ResourceParam: "resourceParam",
	},
)
